import {
    IMessageDataWrapper,
    IMessageParser,
} from '@nitrots/nitro-renderer/src/core';

export interface TimeOfDayData {
    hhmm: string; // "HH:mm"
    phase: 'DAY' | 'DUSK' | 'NIGHT' | 'DAWN';
}

export class TimeOfDayParser implements IMessageParser {
    private _data: TimeOfDayData = {
        hhmm: '00:00',
        phase: 'DAY',
    };

    public flush(): boolean {
        this._data = {
            hhmm: '00:00',
            phase: 'DAY',
        };
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        if (!wrapper) return false;

        // MUST match compose order in TimeOfDayComposer
        this._data.hhmm = wrapper.readString();
        this._data.phase = wrapper.readString() as TimeOfDayData['phase'];

        return true;
    }

    public get data(): TimeOfDayData {
        return this._data;
    }
}
